parameters.jsonBody:
={{ {
  chat_id: $env.ALERTA_TELEGRAM_CHAT_ID,
  parse_mode: 'HTML',
  text: (
    '🚨 <b>ALERTA — ' + ($json.body?.type ?? $json.type ?? 'evento').toUpperCase().replace(/_/g, ' ') + '</b>\n\n' +
    '👤 Lead: <code>' + ($json.body?.visitor_id ?? $json.visitor_id ?? '-') + '</code>\n' +
    '📌 Flujo: F' + ($json.body?.flow ?? $json.flow ?? '?') + '\n' +
    '🌐 Origen: ' + ($json.body?.utm_source ?? $json.utm_source ?? 'desconocido') + '\n' +
    '📍 País: ' + ($json.body?.pais ?? $json.pais ?? '-') + '\n' +
    '🕐 ' + new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' })
  )
} }}
